        endCalled = true;
      } else if (end === null && data !== undefined) {
        results.push(data);
      }
    });

    // Second call without abort
    source(null, (end: boolean | null, data?: number) => {
      if (end === null && data !== undefined) {
        results.push(data);
      }
    });

    expect(results).toEqual([1, 2]);
    expect(endCalled).toBe(false);
  });
